          "humanRow": 9,
          "idea": "Test radius schedules or soft hyperball under NorMuonH",
          "humanMove": "NorMuon/NorMuon-lite uses a weight-decay-free u/w-floor that enforces a minimum update-to-weight ratio instead of hard hyperball radii",
          "matchClass": "mechanism",
